import React from "react";

const PacksPage = () => {
  return (
    <div style={{ padding: "20px", background: "#f5f5f5" }}>

      {/* HEADER */}
      <div style={header}>
        <h1 style={{ marginBottom: "10px" }}>Subscription Packs</h1>
        <p>
          Save up to 25% with our curated grocery bundles. <br />
          Customize your pack and get regular deliveries!
        </p>
      </div>

      {/* FILTER BAR */}
      <div style={filterBar}>
        <div style={{ display: "flex", gap: "15px", alignItems: "center" }}>
          <button style={activeFilter}>All</button>
          <span>Vegetables</span>
          <span>Grocery</span>
          <span>Dairy</span>
          <span style={{ fontSize: "18px" }}>⚗️</span>
        </div>

        <button style={customizeBtn}>+ Customize</button>
      </div>

      {/* CARDS */}
      <div style={grid}>

        {/* CARD 1 */}
        <div style={card}>
          <div style={{ position: "relative" }}>
            <img src="https://images.unsplash.com/photo-1542838132-92c53300491e" style={img} />

            <span style={tagLeft}>🔥 Popular</span>
            <span style={tagRight}>Save ₹300</span>
          </div>

          <div style={content}>
            <p style={subText}>Monthly • Essentials</p>
            <h3>Daily Essentials Pack</h3>
            <p style={desc}>Your everyday grocery needs delivered fresh</p>

            <ul style={list}>
              <li>✔ Rice (5kg)</li>
              <li>✔ Dal (2kg)</li>
              <li>✔ Oil (2L)</li>
              <li style={{ color: "green" }}>+3 more items</li>
            </ul>

            <div style={bottomRow}>
              <div>
                <h3>₹999 <span style={strike}>₹1299</span></h3>
                <p style={small}>/monthly</p>
              </div>
              <button style={btn}>Subscribe</button>
            </div>
          </div>
        </div>

        {/* CARD 2 */}
        <div style={card}>
          <div style={{ position: "relative" }}>
            <img src="https://images.unsplash.com/photo-1512621776951-a57141f2eefd" style={img} />
            <span style={tagLeft}>🔥 Popular</span>
            <span style={tagRight}>Save ₹100</span>
          </div>

          <div style={content}>
            <p style={subText}>Weekly • Vegetables</p>
            <h3>Fresh Veggies Weekly</h3>
            <p style={desc}>Farm-fresh vegetables every week</p>

            <ul style={list}>
              <li>✔ Tomatoes (1kg)</li>
              <li>✔ Onions (1kg)</li>
              <li>✔ Potatoes (2kg)</li>
              <li style={{ color: "green" }}>+2 more items</li>
            </ul>

            <div style={bottomRow}>
              <div>
                <h3>₹399 <span style={strike}>₹499</span></h3>
                <p style={small}>/weekly</p>
              </div>
              <button style={btn}>Subscribe</button>
            </div>
          </div>
        </div>

        {/* CARD 3 */}
        <div style={card}>
          <div style={{ position: "relative" }}>
            <img src="https://images.unsplash.com/photo-1580910051074-3eb694886505" style={img} />
            <span style={tagRight}>Save ₹150</span>
          </div>

          <div style={content}>
            <p style={subText}>Monthly • Dairy</p>
            <h3>Dairy Delight</h3>
            <p style={desc}>Fresh dairy products at your doorstep</p>

            <ul style={list}>
              <li>✔ Milk (30L)</li>
              <li>✔ Curd (4kg)</li>
              <li>✔ Paneer (1kg)</li>
              <li style={{ color: "green" }}>+2 more items</li>
            </ul>

            <div style={bottomRow}>
              <div>
                <h3>₹599 <span style={strike}>₹749</span></h3>
                <p style={small}>/monthly</p>
              </div>
              <button style={btn}>Subscribe</button>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default PacksPage;

//////////////////// STYLES ////////////////////

const header = {
  background: "#6bd36b",
  padding: "40px",
  borderRadius: "10px",
  textAlign: "center"
};

const filterBar = {
  display: "flex",
  justifyContent: "space-between",
  marginTop: "20px",
  marginBottom: "20px"
};

const activeFilter = {
  background: "#6bd36b",
  border: "none",
  padding: "8px 15px",
  borderRadius: "20px"
};

const customizeBtn = {
  background: "#6bd36b",
  border: "none",
  padding: "10px 20px",
  borderRadius: "20px",
  cursor: "pointer"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(3, 1fr)",
  gap: "20px"
};

const card = {
  background: "#fff",
  borderRadius: "12px",
  overflow: "hidden",
  boxShadow: "0 4px 12px rgba(0,0,0,0.1)"
};

const img = {
  width: "100%",
  height: "180px",
  objectFit: "cover"
};

const content = {
